INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.10.81','cb','cb.adi.10','ЧБ Ади 10.81',81,'ঈশ্বরেরে গন্ধমাল্য দিয়া শুভক্ষণে ।
অধিবাস করিলেন আপ্ত-বিপ্রগণে ॥৮১॥','ӣш́варере гандха-ма̄лйа дийа̄ ш́убха-кш̣ан̣е
адхива̄са карилена а̄пта-випра-ган̣е',NULL,NULL),('cb.adi.10.82','cb','cb.adi.10','ЧБ Ади 10.82',82,'দিব্য গন্ধ, চন্দন, তাম্বূল, মালা দিয়া ।
ব্রাহ্মণগণের তুষিলেন হর্ষ হৈয়া ॥৮২॥','дивйа гандха, чандана, та̄мбӯла, ма̄ла̄ дийа̄
бра̄хман̣а-ган̣ере туш̣илена харш̣а хаийа̄',NULL,NULL),('cb.adi.10.83','cb','cb.adi.10','ЧБ Ади 10.83',83,'বল্লভ-আচার্য্য আসি’ যথাবিধিরূপে ।
অধিবাস করাইয়া গেলেন কৌতুকে ॥৮৩॥','валлабха-а̄ча̄рйа а̄си’ йатха̄-видхи-рӯпе
адхива̄са кара̄ийа̄ гелена каутуке',NULL,NULL),('cb.adi.10.84','cb','cb.adi.10','ЧБ Ади 10.84',84,'প্রভাতে উঠিয়া প্রভু করি’ স্নান-দান ।
পিতৃগণে পূজিলেন করিয়া সম্মান ॥৮৪॥','прабха̄те ут̣хийа̄ прабху кари’ сна̄на-да̄на
питр̣-ган̣е пӯджилена карийа̄ сама̄на',NULL,NULL),('cb.adi.10.85','cb','cb.adi.10','ЧБ Ади 10.85',85,'নৃত্য-গীত-বাদ্যে মহা উঠিল মঙ্গল ।
চতুর্দ্দিকে ‘লেহ-দেহ’ শুনি কোলাহল ॥৮৫॥','нр̣тйа-гӣта-ва̄дйе маха̄ ут̣хила ман̇гала
чатур-дике ‘леха-деха’ ш́уни кола̄хала',NULL,NULL),('cb.adi.10.86','cb','cb.adi.10','ЧБ Ади 10.86',86,'কত বা মিলিল আসি’ পতিব্রতাগণ ।
কতেক বা ইষ্ট মিত্র ব্রাহ্মণ সজ্জন ॥৮৬॥','ката ва̄ милила а̄си’ пати-врата̄-ган̣а
катека ва̄ иш̣т̣а митра бра̄хман̣а саджджана',NULL,NULL),('cb.adi.10.87','cb','cb.adi.10','ЧБ Ади 10.87',87,'খই, কলা, সিন্দূর, তাম্বূল, তৈল দিয়া ।
স্ত্রীগণেরে আই তুষিলেন হর্ষ হঞা ॥৮৭॥','кхаи, кала̄, синдӯра, та̄мбӯла, таила дийа̄
стрӣ-ган̣ере а̄и туш̣илена харш̣а хан̃а̄',NULL,NULL),('cb.adi.10.88','cb','cb.adi.10','ЧБ Ади 10.88',88,'দেবগণ, দেববধূগণ—নবরূপে ।
প্রভুর বিবাহে আসি’ আছেন কৌতুকে ॥৮৮॥','дева-ган̣а, дева-вадху-ган̣а — нара-рӯпе
прабхура вива̄хе а̄си’ а̄чхена каутуке',NULL,NULL),('cb.adi.10.89','cb','cb.adi.10','ЧБ Ади 10.89',89,'বল্লভ-আচার্য্য এইমত বিধিক্রমে ।
করিলেন দেব-পিতৃ-কার্য্য হর্ষ-মনে ॥৮৯॥','валлабха-а̄ча̄рйа эи-мата видхи-краме
карилена дева-питр̣-ка̄рйа харш̣а-мане',NULL,NULL),('cb.adi.10.90','cb','cb.adi.10','ЧБ Ади 10.90',90,'তবে প্রভু শুভক্ষণে গোধূলি-সময়ে ।
যাত্রা করি’ আইলেন মিশ্রের আলয়ে ॥৯০॥','табе прабху ш́убха кш̣ан̣е го-дхӯли-самайе
йа̄тра̄ кари’ а̄илена миш́рӣра а̄лайе',NULL,NULL),('cb.adi.10.91','cb','cb.adi.10','ЧБ Ади 10.91',91,'প্রভু আসিলেহ মাত্র, মিশ্র গোষ্ঠী-সনে ।
আনন্দ-সাগরে মগ্ন হৈলা সবে মনে ॥৯১॥','прабху а̄силеха ма̄тра, миш́ра гош̣т̣хӣ-сане
а̄нанда-са̄гаре магна хаила̄ сабе мане',NULL,NULL),('cb.adi.10.92','cb','cb.adi.10','ЧБ Ади 10.92',92,'সম্ভ্রমে আসন দিয়া যথাবিধিরূপে ।
জামাতারে বসাইলা পরম-কৌতুকে ॥৯২॥','самбхраме а̄сана дийа̄ йатха̄-видхи-рӯпе
джа̄ма̄та̄ре васа̄ила̄ парама-каутуке',NULL,NULL),('cb.adi.10.93','cb','cb.adi.10','ЧБ Ади 10.93',93,'শেষে সর্ব্ব-অলঙ্কারে করিয়া ভূষিত ।
লক্ষ্মী-কন্যা আনিলেন প্রভুর সমীপ ॥৯৩॥','ш́еш̣е сарва-алан̇ка̄ре карийа̄ бхӯш̣ита
лакш̣мӣ-канйа̄ а̄ниена прабхура самӣпа',NULL,NULL),('cb.adi.10.94','cb','cb.adi.10','ЧБ Ади 10.94',94,'হরিধ্বনি সর্ব্বলোকে লাগিল করিতে ।
তুলিলেন সভে লক্ষ্মীরে পৃথ্বী হইতে ॥৯৪॥','хари-дхвани сарва-локе ла̄гила карите
тулилена сабхе лакш̣мӣре пр̣тхвӣ хаите',NULL,NULL),('cb.adi.10.95','cb','cb.adi.10','ЧБ Ади 10.95',95,'তবে লক্ষ্মী প্রদক্ষিণ করি’ সপ্তবার ।
যোড়-হস্তে রহিলেন করি’ নমস্কার ॥৯৫॥','табе лакш̣мӣ прадакш̣ин̣а кари’ сапта-ба̄ра
йод̣а-хасте рахилена кари’ намаска̄ра',NULL,NULL),('cb.adi.10.96','cb','cb.adi.10','ЧБ Ади 10.96',96,'তবে শেষে হৈল পুষ্পমালা-ফেলাফেলি ।
লক্ষ্মী-নারায়ণ দোঁহে মহা-কুতূহলী ॥৯৬॥','табе ш́еш̣е хаила пуш̣па-ма̄ла̄-пхела̄-пхели
лакш̣мӣ-на̄ра̄йан̣а дон̇хе маха̄-кутӯхалӣ',NULL,NULL),('cb.adi.10.97','cb','cb.adi.10','ЧБ Ади 10.97',97,'দিব্য-মালা দিয়া লক্ষ্মী প্রভুর চরণে ।
নমস্করি’ করিলেন আত্মসমর্পণে ॥৯৭॥','дивйа-ма̄ла̄ дийа̄ лакш̣мӣ прабхура чаран̣е
намаскари’ карилена а̄тма-самарпане',NULL,NULL),('cb.adi.10.98','cb','cb.adi.10','ЧБ Ади 10.98',98,'সর্ব্বদিকে মহা জয়-জয়-হরি-ধ্বনি ।
উঠিল পরমানন্দ, আর নাহি শুনি ॥৯৮॥','сарва-дике маха̄ джайа-джайа-хари-дхвани
ут̣хила парама̄нанда, а̄ра на̄хи ш́уни',NULL,NULL),('cb.adi.10.99','cb','cb.adi.10','ЧБ Ади 10.99',99,'হেনমতে শ্রীমুখচন্দ্রিকা করি’ রসে ।
বসিলেন প্রভু, লক্ষ্মী করি’ বাম-পাশে ॥৯৯॥','хӣна-мате ш́рӣ-мукха-чандрика̄ кари’ расе
василена прабху, лакш̣мӣ кари ва̄ма-па̄ш́е',NULL,NULL),('cb.adi.10.100','cb','cb.adi.10','ЧБ Ади 10.100',100,'প্রথম-বয়স প্রভু জিনিঞা মদন ।
বাম-পাশে লক্ষ্মী বসিলেন সেইক্ষণ ॥১০০॥','пратхама-вайаса прабху джинин̃а̄ мадана
ва̄ма-па̄ш́е лакш̣мӣ василена сеикш̣ан̣а',NULL,NULL),('cb.adi.10.101','cb','cb.adi.10','ЧБ Ади 10.101',101,'কি শোভা, কি সুখ সে হইল মিশ্র-ঘরে ।
কোন্ জন তাহা বর্ণিবারে শক্তি ধরে ? ॥১০১॥','ки ш́обха̄, ки, сукха се хаила миш́ра-гхаре
кон джана та̄ха̄ варн̣иба̄ре ш́акти дхаре?',NULL,NULL),('cb.adi.10.102','cb','cb.adi.10','ЧБ Ади 10.102',102,'তবে শেষে বল্লভ করিতে কন্যা-দান ।
বসিলেন যেহেন ভীষ্মক বিদ্যমান ॥১০২॥
যে-চরণে পাদ্য দিয়া শঙ্কর-ব্রহ্মার ।
জগৎ সৃজিতে শক্তি হইল সবার ॥১০৩॥
হেন পাদপদ্মে পাদ্য দিলা বিপ্রবর ।
বস্ত্র-মাল্য-চন্দনে ভূষিয়া কলেবর ॥১০৪॥','табе ш́еш̣е валлабха карите канйа̄ да̄на
василена йехена бхӣш̣мака видйама̄на
йе-чаран̣е па̄дйа дийа̄ ш́ан̇кара-брахма̄ра
джагад ср̣джите ш́акти хаила саба̄ра
хӣнапа̄да-падме па̄дйа дила̄ випра-вара
вастра-ма̄лйа-чандане бхӯш̣ийа̄ калевара',NULL,NULL),('cb.adi.10.105','cb','cb.adi.10','ЧБ Ади 10.105',105,'যথাবিধিরূপে কন্যা করি’ সমর্পণ ।
আনন্দ-সাগরে মগ্ন হইলা ব্রাহ্মণ ॥১০৫॥','йатха̄-видхи-рӯпе канйа̄ кари’ самарпан̣а
а̄нанда-са̄гаре магн̇а хаила̄ бра̄хман̣а',NULL,NULL),('cb.adi.10.106','cb','cb.adi.10','ЧБ Ади 10.106',106,'তবে যত কিছু কুল-ব্যবহার আছে ।
পতিব্রতাগণ তাহা করিলেন পাছে ॥১০৬॥','табе йатха кичху кула-вйаваха̄на а̄чхе
пати-врата̄-ган̣а та̄ха̄ карилена па̄чхе',NULL,NULL),('cb.adi.10.107','cb','cb.adi.10','ЧБ Ади 10.107',107,'সে রাত্রি তথায় থাকি’ তবে আর দিনে ।
নিজ-গৃহে চলিলেন প্রভু লক্ষ্মী-সনে ॥১০৭॥','се ра̄три татха̄йа тха̄ки табе а̄ра дине
ниджа-гр̣хе чалилена прабху лакш̣мӣ-сане',NULL,NULL),('cb.adi.10.108','cb','cb.adi.10','ЧБ Ади 10.108',108,'লক্ষ্মীর সহিত প্রভু চড়িয়া দোলায় ।
আইসেন, দেখিতে সকল লোক ধায় ॥১০৮॥','лакш̣мӣра сахита прабху чад̣ийа̄ дола̄йа
а̄исена, декхите сакхите сакала лока дха̄йа',NULL,NULL),('cb.adi.10.109','cb','cb.adi.10','ЧБ Ади 10.109',109,'গন্ধ, মাল্য, অলঙ্কার, মুকুট, চন্দন ।
কজ্জলে উজ্জ্বল দুই লক্ষ্মী-নারায়ণ ॥১০৯॥','гандха, ма̄лйа, алан̇ка̄ра, мукут̣а, чандана
каджджвале уджджвала дуи лакш̣мӣ-на̄ра̄йан̣а',NULL,NULL),('cb.adi.10.110','cb','cb.adi.10','ЧБ Ади 10.110',110,'সর্ব্ব-লোক দেখি’ মাত্র ‘ধন্য ধন্য’ বোলে ।
বিশেষে স্ত্রীগণ অতি পড়িলেন ভোলে ॥১১০॥','сарва-лока декхи’ ма̄тра ‘дханйа дханйа’ боле
виш́еш̣е стрӣ-ган̣а ати пад̣илена бхоле',NULL,NULL),('cb.adi.10.111','cb','cb.adi.10','ЧБ Ади 10.111',111,'“কতকাল এ বা ভাগ্যবতী হর-গৌরী ।
নিষ্কপটে সেবিলেন কতভক্তি করি’ ॥১১১॥','‘ката-ка̄ла э ва̄ бха̄гйаватӣ хара-гаурӣ
ниш̣капат̣е севидена ката-бхакти кари',NULL,NULL),('cb.adi.10.112','cb','cb.adi.10','ЧБ Ади 10.112',112,'অল্প-ভাগ্যে কন্যার কি হেন স্বামী মিলে ? ।
এই হর-গৌরী হেন বুঝি”—কেহ বোলে ॥১১২॥','алпа-бха̄гйе канйа̄ра ки хена сва̄мӣ миле?
эи хара-гаурӣ хӣнабуджхи’ — кеха боле',NULL,NULL),('cb.adi.10.113','cb','cb.adi.10','ЧБ Ади 10.113',113,'কেহ বোলে,—“ইন্দ্র-শচী, রতি বা মদন” ।
কোন নারী বোলে,—“এই লক্ষ্মী-নারায়ণ” ॥১১৩॥','кеха боле — ‘индра-ш́ачӣ, рати ва̄ мадана’
кона на̄рӣ боле — ‘еи лакш̣мӣ-на̄ра̄йан̣а’',NULL,NULL),('cb.adi.10.114','cb','cb.adi.10','ЧБ Ади 10.114',114,'কোন নারীগণ বোলে,—“যেন সীতা-রাম ।
দোলোপরি শোভিয়াছে অতি-অনুপম” ॥১১৪॥','кона нарӣ-ган̣а боле — ‘йена сӣта-рама',NULL,NULL),('cb.adi.10.115','cb','cb.adi.10','ЧБ Ади 10.115',115,'এইমত নানারূপে বোলে নারীগণে ।
শুভদৃষ্ট্যে সবে দেখে লক্ষ্মী-নারায়ণে ॥১১৫॥','эи-мата на̄на̄-рӯпе боле на̄рӣ-ган̣е
ш́убха-др̣ш̣т̣йе сабе декхе лакш̣мӣ-на̄ра̄йан̣а',NULL,NULL),('cb.adi.10.116','cb','cb.adi.10','ЧБ Ади 10.116',116,'হেনমতে নৃত্য-গীত-বাদ্য-কোলাহলে ।
নিজগৃহে প্রভু আইলেন সন্ধ্যাকালে ॥১১৬॥','хӣна-мате нр̣тйа-гӣта-ва̄дйа-кола̄хале
ниджа-гр̣хе прабху а̄илена сандхйа̄-ка̄ле',NULL,NULL),('cb.adi.10.117','cb','cb.adi.10','ЧБ Ади 10.117',117,'তবে শচীদেবী বিপ্রপত্নীগণ লৈয়া ।
পুত্ত্রবধূ ঘরে আনিলেন হর্ষ হৈয়া ॥১১৭॥','табе ш́ачӣдевӣ випра-патнӣ-ган̣а лаийа̄
путра-вадхӯ гхаре а̄нилена харш̣а хаийа̄',NULL,NULL),('cb.adi.10.118','cb','cb.adi.10','ЧБ Ади 10.118',118,'দ্বিজ-আদি যত জাতি নট বাজনিয়া ।
সবারে তুষিলা ধন, বস্ত্র, বাক্য দিয়া ॥১১৮॥','двиджа-а̄ди йата джа̄ти нат̣а ба̄джанийа̄
саба̄ре туш̣ила̄ дхана, вастра, ва̄кйа дийа̄',NULL,NULL),('cb.adi.10.119','cb','cb.adi.10','ЧБ Ади 10.119',119,'যে শুনয়ে প্রভুর বিবাহ-পুণ্য-কথা ।
তাহার সংসার-বন্ধ না হয় সর্ব্বথা ॥১১৯॥','йе ш́унайе прабхура вива̄ха-пун̣йа-катха̄
та̄ха̄ра сам̇са̄ра-бандха на̄ хайа сарватха̄',NULL,NULL),('cb.adi.10.120','cb','cb.adi.10','ЧБ Ади 10.120',120,'প্রভুপার্শ্বে লক্ষ্মীর হইল অবস্থান ।
